#include <bits/stdc++.h>
using namespace std;
const int N=22000005;
string s,s2;
int len[N],ans,t;
int main()
{
	cin>>t;
	while(t--)
	{
		cin>>s2;
		string s="?#";
		for(int i=0;i<s2.size();i++)
		{
			s+=s2[i];
			s+="#";
		}
		int n=s.size();
		int mx=0,mid=0;
		ans=0;
		for(int i=1;i<=n;i++)
		{
			if(mx>i)
			{
				len[i]=min(len[2*mid-i],mx-i);
			}
			else len[i]=1;
			while(s[i+len[i]]==s[i-len[i]])
			{
				len[i]++;
			}
			if(i+len[i]>mx)
			{
				mx=i+len[i];
				mid=i;
			}
			ans=max(ans,len[i]-1);
		}
		cout<<ans<<'\n';
	}

	return 0;
}
